from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "dateofretirement":
            return f"retired on {fmt_date(obj)}"
        if p == "nationality":
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "is an American"
            if low_obj.startswith("the "):
                return f"is from {obj}"
            else:
                return f"is from the {obj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # First, collect mission‑crew relationships so we can produce a single sentence per mission
    from collections import defaultdict
    mission_to_astronauts = defaultdict(list)
    skip_triples = set()          # triples that will be handled separately (mission/crewMembers)

    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        if pred == "mission":
            mission_to_astronauts[t.object].append(t.subject)
            skip_triples.add(t)
        elif pred == "crewmembers":
            mission_to_astronauts[t.subject].append(t.object)
            skip_triples.add(t)

    # Group the remaining triples by subject
    groups = defaultdict(list)
    for t in triples:
        if t in skip_triples:
            continue
        groups[t.subject].append(t)

    sentences = []

    # Create sentences for mission crew lists (combine all astronauts for the same mission)
    for mission, astronauts in mission_to_astronauts.items():
        if not astronauts:
            continue
        # Remove duplicates while preserving order
        seen = set()
        uniq_astronauts = []
        for a in astronauts:
            if a not in seen:
                seen.add(a)
                uniq_astronauts.append(a)
        if len(uniq_astronauts) == 1:
            crew_str = uniq_astronauts[0]
        else:
            crew_str = ", ".join(uniq_astronauts[:-1]) + f" and {uniq_astronauts[-1]}"
        sentences.append(f"{crew_str} were crew members of {mission}.")

    # Build sentences for the remaining subjects
    for subj, items in groups.items():
        descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not descriptors:
            continue
        # Clean descriptors: remove leading subject repetitions and trailing periods
        clean_desc = []
        for d in descriptors:
            d = d.strip()
            if d.lower().startswith(subj.lower()):
                d = d[len(subj):].strip()
            clean_desc.append(d.rstrip('.'))
        # Join descriptors into a fluent clause
        if len(clean_desc) == 1:
            body = clean_desc[0]
        elif len(clean_desc) == 2:
            body = f"{clean_desc[0]} and {clean_desc[1]}"
        else:
            body = ", ".join(clean_desc[:-1]) + f", and {clean_desc[-1]}"
        sentences.append(f"{subj} {body}.")

    # Combine all sentences into a single paragraph
    return " ".join(sentences)

# EVOLVE-BLOCK-END
